SourceCode.Declaration:
/// <summary>
/// This class is an extension of ReturnTable form, SalesLine datasource and DepositRate field.
/// </summary>
[ExtensionOf(formDataFieldStr(ReturnTable, SalesLine, ETGDepositRate))]
internal final class ETGReturnTable_SalesLine_DepositRate_Extension
{
}

Method.Source:
/// <summary>
/// When DepositRate field is modified, then calculating the deposit amount field.
/// </summary>
public void modified()
{
    next modified();

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        FormDataObject  formDataObject = any2Object(this) as FormDataObject;
        FormDataSource  formDataSource = formDataObject.datasource();
        SalesLine       salesLine      = formDataSource.cursor();

        salesLine.ETGDepositAmount = salesLine.ETGDepositRate * salesLine.ExpectedRetQty;
    }
}
